      out.write("    function setPreset(type) {\r\n");
      out.write("        var today = new Date();\r\n");
      out.write("        var start, end;\r\n");
      out.write("        if (type === 'thisWeek') {\r\n");
      out.write("            var day = today.getDay(); \r\n");
      out.write("            var diffToMon = (day === 0) ? -6 : 1 - day;\r\n");
      out.write("            start = new Date(today); start.setDate(today.getDate() + diffToMon);\r\n");
      out.write("            end   = new Date(start); end.setDate(start.getDate() + 6);\r\n");
      out.write("        } else if (type === 'lastWeek') {\r\n");
      out.write("            var day = today.getDay();\r\n");
      out.write("            var diffToMon = (day === 0) ? -6 : 1 - day;\r\n");
      out.write("            start = new Date(today); start.setDate(today.getDate() + diffToMon - 7);\r\n");
      out.write("            end   = new Date(start); end.setDate(start.getDate() + 6);\r\n");
      out.write("        } else if (type === 'thisMonth') {\r\n");
      out.write("            start = new Date(today.getFullYear(), today.getMonth(), 1);\r\n");
      out.write("            end   = new Date(today.getFullYear(), today.getMonth() + 1, 0);\r\n");
      out.write("        } else if (type === 'lastMonth') {\r\n");
      out.write("            start = new Date(today.getFullYear(), today.getMonth() - 1, 1);\r\n");
      out.write("            end   = new Date(today.getFullYear(), today.getMonth(), 0);\r\n");
      out.write("        }\r\n");
      out.write("        document.getElementById('startDateInput').value = toDateStr(start);\r\n");
      out.write("        document.getElementById('endDateInput').value   = toDateStr(end);\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
